section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/design-system-changelog-template.json",
  "title": "Design System Changelog Template",
  "type": "object",
  "required": [
    "artefact_id",
    "release_id",
    "released_at",
    "components_changed",
    "breaking_changes",
    "migration_guide_ref",
    "impacted_teams",
    "risk_level",
    "rollback_plan",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "release_id": {
      "type": "string",
      "description": "release_id",
      "minLength": 1
    },
    "released_at": {
      "type": "string",
      "description": "released_at (ISO-8601)",
      "format": "date-time"
    },
    "components_changed": {
      "type": "array",
      "description": "components_changed (array)",
      "minItems": 1
    },
    "breaking_changes": {
      "type": "array",
      "description": "breaking_changes (array)",
      "minItems": 1
    },
    "migration_guide_ref": {
      "type": "string",
      "description": "migration_guide_ref",
      "minLength": 1
    },
    "impacted_teams": {
      "type": "array",
      "description": "impacted_teams (array)",
      "minItems": 1
    },
    "risk_level": {
      "type": "string",
      "description": "risk_level",
      "minLength": 1
    },
    "rollback_plan": {
      "type": "string",
      "description": "rollback_plan",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
